import{_ as d,o as e,c as r,a2 as a}from"./chunks/framework._O8Cueap.js";const p=JSON.parse('{"title":"Core Tables","description":"","frontmatter":{},"headers":[],"relativePath":"database/schema-core.md","filePath":"database/schema-core.md"}'),o={name:"database/schema-core.md"};function s(n,t,i,l,c,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="core-tables" tabindex="-1">Core Tables <a class="header-anchor" href="#core-tables" aria-label="Permalink to &quot;Core Tables&quot;">​</a></h1><p>Tenancy, Agent, Workflow, and Execution tables. For the ER diagram and enums, see <a href="/open-agent-orchestra/database/schema.html">Schema Overview</a>.</p><h2 id="tenancy-tables" tabindex="-1">Tenancy Tables <a class="header-anchor" href="#tenancy-tables" aria-label="Permalink to &quot;Tenancy Tables&quot;">​</a></h2><h3 id="workspaces" tabindex="-1">workspaces <a class="header-anchor" href="#workspaces" aria-label="Permalink to &quot;workspaces&quot;">​</a></h3><p>Tenant isolation boundary. All entities reference a workspace.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>name</td><td>varchar(200)</td><td></td></tr><tr><td>slug</td><td>varchar(100)</td><td>Unique, URL-safe identifier</td></tr><tr><td>description</td><td>text</td><td></td></tr><tr><td>isDefault</td><td>boolean</td><td>Default workspace cannot be deleted</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="users" tabindex="-1">users <a class="header-anchor" href="#users" aria-label="Permalink to &quot;users&quot;">​</a></h3><p>Independent auth (email/password/bcrypt). Supports multiple auth providers (database, LDAP).</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td>Cascade delete</td></tr><tr><td>email</td><td>varchar(255)</td><td>Unique</td></tr><tr><td>name</td><td>varchar(100)</td><td></td></tr><tr><td>passwordHash</td><td>text</td><td>bcrypt (nullable for LDAP users)</td></tr><tr><td>authProvider</td><td>auth_provider_type</td><td><code>database</code> or <code>ldap</code> (default: <code>database</code>)</td></tr><tr><td>role</td><td>user_role</td><td>Default: <code>creator_user</code></td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><h2 id="agent-tables" tabindex="-1">Agent Tables <a class="header-anchor" href="#agent-tables" aria-label="Permalink to &quot;Agent Tables&quot;">​</a></h2><h3 id="agents" tabindex="-1">agents <a class="header-anchor" href="#agents" aria-label="Permalink to &quot;agents&quot;">​</a></h3><p>AI agent definitions.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td>Cascade delete</td></tr><tr><td>userId</td><td>UUID</td><td>Owner user</td></tr><tr><td>name</td><td>varchar(100)</td><td></td></tr><tr><td>description</td><td>text</td><td></td></tr><tr><td>sourceType</td><td>agent_source_type</td><td>Default: <code>github_repo</code></td></tr><tr><td>gitRepoUrl</td><td>varchar(500)</td><td>Required for <code>github_repo</code></td></tr><tr><td>gitBranch</td><td>varchar(100)</td><td>Default: <code>main</code></td></tr><tr><td>agentFilePath</td><td>varchar(300)</td><td>Path to .md in repo</td></tr><tr><td>skillsDirectory</td><td>varchar(500)</td><td>Skills directory path</td></tr><tr><td>skillsPaths</td><td>varchar(300)[]</td><td>Explicit skill file paths</td></tr><tr><td>githubTokenEncrypted</td><td>text</td><td>AES-256-GCM encrypted</td></tr><tr><td>githubTokenCredentialId</td><td>varchar(100)</td><td>References credential variable</td></tr><tr><td>builtinToolsEnabled</td><td>jsonb</td><td>Array of enabled built-in tool names</td></tr><tr><td>mcpJsonTemplate</td><td>text</td><td>Jinja2 template for mcp.json (rendered with variables before session)</td></tr><tr><td>scope</td><td>resource_scope</td><td>Default: <code>user</code>. Immutable</td></tr><tr><td>version</td><td>integer</td><td>Auto-incremented on every update. Default: 1</td></tr><tr><td>status</td><td>agent_status</td><td></td></tr><tr><td>lastSessionAt</td><td>timestamp</td><td></td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="agent-files" tabindex="-1">agent_files <a class="header-anchor" href="#agent-files" aria-label="Permalink to &quot;agent_files&quot;">​</a></h3><p>Database-stored agent files (for <code>sourceType: database</code>).</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td>Cascade delete</td></tr><tr><td>filePath</td><td>varchar(500)</td><td>Relative path (e.g., <code>agent.md</code>, <code>skills/research.md</code>)</td></tr><tr><td>content</td><td>text</td><td>Markdown content</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(agentId, filePath)</td></tr></tbody></table><h3 id="agent-versions" tabindex="-1">agent_versions <a class="header-anchor" href="#agent-versions" aria-label="Permalink to &quot;agent_versions&quot;">​</a></h3><p>Immutable snapshots of agent config at each version, for audit trail.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td>Cascade delete</td></tr><tr><td>version</td><td>integer</td><td>Matches agents.version at time of change</td></tr><tr><td>snapshot</td><td>jsonb</td><td>Full agent config + files snapshot</td></tr><tr><td>changedBy</td><td>UUID</td><td>User who made the change</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(agentId, version)</td></tr></tbody></table><h3 id="mcp-server-configs" tabindex="-1">mcp_server_configs <a class="header-anchor" href="#mcp-server-configs" aria-label="Permalink to &quot;mcp_server_configs&quot;">​</a></h3><p>MCP server configurations per agent.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td></td></tr><tr><td>serverType</td><td>enum</td><td><code>custom</code> or system-managed <code>oao_platform</code></td></tr><tr><td>name</td><td>varchar(100)</td><td>Display name</td></tr><tr><td>description</td><td>varchar(500)</td><td></td></tr><tr><td>command</td><td>varchar(200)</td><td>Process command (<code>node</code>, <code>npx</code>, <code>python</code>)</td></tr><tr><td>args</td><td>jsonb</td><td>Command arguments array</td></tr><tr><td>envMapping</td><td>jsonb</td><td>Credential key → env var mapping</td></tr><tr><td>isEnabled</td><td>boolean</td><td></td></tr><tr><td>writeTools</td><td>jsonb</td><td>Tool names requiring permission</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><p>Every new agent gets one default <code>oao_platform</code> row. That system-managed row points at the bundled OAO Platform MCP server and carries per-session auth/env at runtime rather than storing secrets in the table.</p><h2 id="workflow-tables" tabindex="-1">Workflow Tables <a class="header-anchor" href="#workflow-tables" aria-label="Permalink to &quot;Workflow Tables&quot;">​</a></h2><h3 id="workflows" tabindex="-1">workflows <a class="header-anchor" href="#workflows" aria-label="Permalink to &quot;workflows&quot;">​</a></h3><p>Multi-step execution templates.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td>Cascade delete</td></tr><tr><td>userId</td><td>UUID</td><td>Owner</td></tr><tr><td>name</td><td>varchar(200)</td><td></td></tr><tr><td>description</td><td>text</td><td></td></tr><tr><td>labels</td><td>varchar(50)[]</td><td>Filterable tags (GIN indexed)</td></tr><tr><td>isActive</td><td>boolean</td><td></td></tr><tr><td>maxConcurrentExecutions</td><td>integer</td><td>Default: 1</td></tr><tr><td>version</td><td>integer</td><td>Auto-incremented. Default: 1</td></tr><tr><td>defaultAgentId</td><td>UUID FK → agents</td><td>Optional</td></tr><tr><td>defaultModel</td><td>varchar(100)</td><td>Optional</td></tr><tr><td>defaultReasoningEffort</td><td>reasoning_effort</td><td>Optional</td></tr><tr><td>workerRuntime</td><td>worker_runtime</td><td><code>static</code> or <code>ephemeral</code>. Default: <code>static</code></td></tr><tr><td>stepAllocationTimeoutSeconds</td><td>integer</td><td>Default: 300. Max wait for a step to leave <code>pending</code> while allocating a runtime</td></tr><tr><td>scope</td><td>resource_scope</td><td>Default: <code>user</code>. Immutable</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="workflow-steps" tabindex="-1">workflow_steps <a class="header-anchor" href="#workflow-steps" aria-label="Permalink to &quot;workflow_steps&quot;">​</a></h3><p>Ordered steps in a workflow.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workflowId</td><td>UUID FK → workflows</td><td>Cascade delete</td></tr><tr><td>name</td><td>varchar(200)</td><td></td></tr><tr><td>promptTemplate</td><td>text</td><td>Markdown with optional <code>&lt;PRECEDENT_OUTPUT&gt;</code></td></tr><tr><td>stepOrder</td><td>integer</td><td>1-indexed</td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td>Optional</td></tr><tr><td>model</td><td>varchar(100)</td><td>Optional override</td></tr><tr><td>reasoningEffort</td><td>reasoning_effort</td><td>Optional</td></tr><tr><td>workerRuntime</td><td>worker_runtime</td><td>Optional override. Falls back to <code>workflows.workerRuntime</code></td></tr><tr><td>timeoutSeconds</td><td>integer</td><td>Default: 300</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(workflowId, stepOrder)</td></tr></tbody></table><h3 id="workflow-versions" tabindex="-1">workflow_versions <a class="header-anchor" href="#workflow-versions" aria-label="Permalink to &quot;workflow_versions&quot;">​</a></h3><p>Immutable snapshots of workflow config + steps at each version, for audit trail.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workflowId</td><td>UUID FK → workflows</td><td>Cascade delete</td></tr><tr><td>version</td><td>integer</td><td>Matches workflows.version at time of change</td></tr><tr><td>snapshot</td><td>jsonb</td><td>Full workflow config + steps snapshot</td></tr><tr><td>changedBy</td><td>UUID</td><td>User who made the change</td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr><tr><td></td><td></td><td>UNIQUE(workflowId, version)</td></tr></tbody></table><h3 id="triggers" tabindex="-1">triggers <a class="header-anchor" href="#triggers" aria-label="Permalink to &quot;triggers&quot;">​</a></h3><p>Trigger configurations for workflows.</p><blockquote><p>Triggers can be edited or deleted at any time via <code>PUT /api/triggers/:id</code> and <code>DELETE /api/triggers/:id</code>. Webhook paths must remain unique across all webhook triggers.</p></blockquote><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workflowId</td><td>UUID FK → workflows</td><td></td></tr><tr><td>triggerType</td><td>trigger_type</td><td></td></tr><tr><td>configuration</td><td>jsonb</td><td>Type-specific config</td></tr><tr><td>isActive</td><td>boolean</td><td></td></tr><tr><td>lastFiredAt</td><td>timestamp</td><td></td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><p><strong>Configuration JSONB examples:</strong></p><ul><li><strong>Cron</strong>: <code>{ &quot;cron&quot;: &quot;0 9 * * 1-5&quot;, &quot;timezone&quot;: &quot;America/New_York&quot; }</code></li><li><strong>Datetime</strong>: <code>{ &quot;datetime&quot;: &quot;2025-01-15T09:00:00Z&quot; }</code> (one-shot, auto-deactivates)</li><li><strong>Webhook</strong>: <code>{ &quot;secret&quot;: &quot;hmac-secret-encrypted&quot; }</code></li><li><strong>Event</strong>: <code>{ &quot;eventName&quot;: &quot;workflow.completed&quot;, &quot;conditions&quot;: { &quot;status&quot;: &quot;completed&quot; } }</code></li></ul><h2 id="conversation-tables" tabindex="-1">Conversation Tables <a class="header-anchor" href="#conversation-tables" aria-label="Permalink to &quot;Conversation Tables&quot;">​</a></h2><h3 id="conversations" tabindex="-1">conversations <a class="header-anchor" href="#conversations" aria-label="Permalink to &quot;conversations&quot;">​</a></h3><p>Persisted interactive chat threads between a user and a selected agent.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workspaceId</td><td>UUID FK → workspaces</td><td>Cascade delete</td></tr><tr><td>userId</td><td>UUID FK → users</td><td>Conversation owner</td></tr><tr><td>agentId</td><td>UUID FK → agents</td><td>Nullable if the source agent is deleted later</td></tr><tr><td>agentNameSnapshot</td><td>varchar(100)</td><td>Stored display name at conversation creation time</td></tr><tr><td>title</td><td>varchar(200)</td><td>User-supplied or auto-generated</td></tr><tr><td>status</td><td>conversation_status</td><td><code>active</code> or <code>archived</code></td></tr><tr><td>lastMessageAt</td><td>timestamp</td><td>Updated whenever a turn is added</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="conversation-messages" tabindex="-1">conversation_messages <a class="header-anchor" href="#conversation-messages" aria-label="Permalink to &quot;conversation_messages&quot;">​</a></h3><p>Stored user and assistant turns for each conversation.</p><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>conversationId</td><td>UUID FK → conversations</td><td>Cascade delete</td></tr><tr><td>role</td><td>conversation_message_role</td><td><code>user</code> or <code>assistant</code></td></tr><tr><td>status</td><td>conversation_message_status</td><td><code>pending</code>, <code>completed</code>, <code>failed</code></td></tr><tr><td>content</td><td>text</td><td>Assistant messages stream into this field as deltas arrive</td></tr><tr><td>model</td><td>varchar(100)</td><td>Recorded for assistant turns when available</td></tr><tr><td>error</td><td>text</td><td>Failure message for failed assistant turns</td></tr><tr><td>metadata</td><td>jsonb</td><td>Reasoning trace and tool-call summary</td></tr><tr><td>createdAt, updatedAt</td><td>timestamp</td><td></td></tr></tbody></table><h2 id="execution-tables" tabindex="-1">Execution Tables <a class="header-anchor" href="#execution-tables" aria-label="Permalink to &quot;Execution Tables&quot;">​</a></h2><h3 id="workflow-executions" tabindex="-1">workflow_executions <a class="header-anchor" href="#workflow-executions" aria-label="Permalink to &quot;workflow_executions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workflowId</td><td>UUID FK → workflows</td><td></td></tr><tr><td>triggerId</td><td>UUID FK → triggers</td><td></td></tr><tr><td>triggerMetadata</td><td>jsonb</td><td>Webhook payload, cron tick, retry info</td></tr><tr><td>workflowVersion</td><td>integer</td><td>Snapshot version at trigger time</td></tr><tr><td>workflowSnapshot</td><td>jsonb</td><td>Full workflow + steps snapshot (immutable, including worker runtime overrides and allocation timeout)</td></tr><tr><td>status</td><td>execution_status</td><td></td></tr><tr><td>currentStep</td><td>integer</td><td>1-indexed</td></tr><tr><td>totalSteps</td><td>integer</td><td></td></tr><tr><td>startedAt, completedAt</td><td>timestamp</td><td></td></tr><tr><td>error</td><td>text</td><td></td></tr><tr><td>createdAt</td><td>timestamp</td><td></td></tr></tbody></table><h3 id="step-executions" tabindex="-1">step_executions <a class="header-anchor" href="#step-executions" aria-label="Permalink to &quot;step_executions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Column</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td>id</td><td>UUID PK</td><td></td></tr><tr><td>workflowExecutionId</td><td>UUID FK → workflow_executions</td><td></td></tr><tr><td>workflowStepId</td><td>UUID FK → workflow_steps</td><td></td></tr><tr><td>stepOrder</td><td>integer</td><td></td></tr><tr><td>agentVersion</td><td>integer</td><td>Snapshot of agent.version when step executes</td></tr><tr><td>agentSnapshot</td><td>jsonb</td><td>Full agent config snapshot at execution time (immutable)</td></tr><tr><td>resolvedPrompt</td><td>text</td><td>Prompt with variables replaced</td></tr><tr><td>output</td><td>text</td><td>Copilot session response</td></tr><tr><td>reasoningTrace</td><td>jsonb</td><td>Tool calls, intermediate thoughts</td></tr><tr><td>liveOutput</td><td>jsonb</td><td>Array of intermediate events streamed during execution</td></tr><tr><td>status</td><td>step_status</td><td></td></tr><tr><td>startedAt, completedAt</td><td>timestamp</td><td></td></tr><tr><td>error</td><td>text</td><td></td></tr></tbody></table>',51)])])}const m=d(o,[["render",s]]);export{p as __pageData,m as default};
